1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	interface Item {
12	  type: string;
13	  cursed?: boolean;
14	  enchantment?: number;
15	}
16	
17	const CURSE_RATE = 0.5;
18	const HIGH_ENCHANTMENT_THRESHOLD = 5;
19	const HIGH_ENCHANTMENT_RATE = 0.3;
20	const LOYALTY_THRESHOLD = 2;
21	const LOYALTY_RATE = 0.2;
22	
23	interface QuoteStep {
24	  op: "quote";
25	  items: Item[];
26	}
27	
28	interface Customer {
29	  yearsWithMHPCO: number;
30	}
31	
32	interface Scenario {
33	  customer: Customer;
34	  steps: QuoteStep[];
35	}
36	
37	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
38	const COMPONENT_BASE = 25;
39	const BLOCK_SIZE = 3;
40	const BLOCK_BASE = 60;
41	
42	const componentBase = (count: number): number =>
43	  count === BLOCK_SIZE ? BLOCK_BASE : count * COMPONENT_BASE;
44	
45	const unitBase = (type: string): number =>
46	  COMPONENT_TYPES.has(type) ? COMPONENT_BASE : (BASE_PREMIUMS[type] ?? 0);
47	
48	const baseForType = (type: string, count: number): number =>
49	  COMPONENT_TYPES.has(type)
50	    ? componentBase(count)
51	    : unitBase(type) * count;
52	
53	const countByType = (items: Item[]): Map<string, number> =>
54	  items.reduce(
55	    (counts, item) =>
56	      counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
57	    new Map<string, number>(),
58	  );
59	
60	const baseForItems = (items: Item[]): number =>
61	  [...countByType(items)].reduce(
62	    (total, [type, count]) => total + baseForType(type, count),
63	    0,
64	  );
65	
66	const isHighlyEnchanted = (item: Item): boolean =>
67	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
68	
69	const surchargeRate = (item: Item): number =>
70	  ((item.cursed ?? false) ? CURSE_RATE : 0) +
71	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_RATE : 0);
72	
73	const itemSurcharges = (item: Item): number =>
74	  unitBase(item.type) * surchargeRate(item);
75	
76	const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
77	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? policyBase * LOYALTY_RATE : 0;
78	
79	const priceQuote = (items: Item[], customer: Customer): { premium: number } => {
80	  const policyBase = baseForItems(items);
81	  const surcharges = items.reduce((sum, item) => sum + itemSurcharges(item), 0);
82	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_RATE;
83	  const premium = Math.ceil(
84	    policyBase +
85	      surcharges +
86	      firstInsuranceSurcharge -
87	      loyaltyDiscount(policyBase, customer) +
88	      PROCESSING_FEE,
89	  );
90	  return { premium };
91	};
92	
93	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
94	  const results = scenario.steps.map((step) =>
95	    priceQuote(step.items, scenario.customer),
96	  );
97	  return { results };
98	};
